import { useEffect, useRef } from 'react';

const CanvasBackground = () => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    let width, height, animationId;

    const resize = () => {
      // Set the canvas size to match its container
      const { clientWidth, clientHeight } = canvas.parentNode;
      canvas.width = clientWidth;
      canvas.height = clientHeight;

      // Update the width and height variables
      width = canvas.width;
      height = canvas.height;
    };

    const col = (x, y, r, g, b) => {
      ctx.fillStyle = `rgb(${r}, ${g}, ${b})`;
      ctx.fillRect(x, y, 1, 1);
    };

    const R = (x, y, t) => {
      return Math.floor(192 + 64 * Math.cos((x * x - y * y) / 300 + t));
    };

    const G = (x, y, t) => {
      return Math.floor(192 + 64 * Math.sin((x * x * Math.cos(t / 4) + y * y * Math.sin(t / 3)) / 300));
    };

    const B = (x, y, t) => {
      return Math.floor(192 + 64 * Math.sin(5 * Math.sin(t / 9) + ((x - 100) * (x - 100) + (y - 100) * (y - 100)) / 1100));
    };

    const draw = (t) => {
      for (let x = 0; x <= width; x++) {
        for (let y = 0; y <= height; y++) {
          col(x, y, R(x, y, t), G(x, y, t), B(x, y, t));
        }
      }

      animationId = requestAnimationFrame(() => {
        draw(t + 0.005);
      });
    };

    resize();
    draw(0);

    // Clean up the animation frame when the component unmounts
    return () => {
      cancelAnimationFrame(animationId);
    };
  }, []);

  return <canvas ref={canvasRef} className="CanvasBackground" />;
};

export default CanvasBackground;
